ncData.valueScript:
//======================================================================
  // Read and parse the data from the countertop segments
  //======================================================================

  // Read the attribute of the countertop info (which are the information from the segments)
  const jsonString = partSelf.pa_CountertopInfo;

  try {
    const parsed = JSON.parse(jsonString);

    //======================================================================
    // Add the cutouts
    //======================================================================

    if (Array.isArray(parsed.Countertops)) {
      parsed.Countertops.forEach((itemStr: string) => {
        try {
          const item = JSON.parse(itemStr);

          // If there is a cutout in the segment
          if (item.CutoutData) {
            const cutoutData = JSON.parse(item.CutoutData);
            const cutOut = this.addncout_CountertopCutoutRectangular();
            cutOut.nc_DrawingRelevant = true;
            cutOut.nc_MprRelevant = true;
            cutOut.nc_LA = cutoutData.CutWidth;
            cutOut.nc_BR = cutoutData.CutDepth;
            cutOut.nc_RD = cutoutData.CutRadius;
            cutOut.nc_XA = cutoutData.CutPosX;
            cutOut.nc_YA = cutoutData.CutPosY + cutoutData.CutDepth / 2;
            cutOut.nc_Side = "Top";
            cutOut.nc_Supplier = cutoutData.Supplier;
            cutOut.nc_ArticleId = cutoutData.Id;
            cutOut.nc_KO = "00";
            cutOut.nc_TOOL = "139";
            cutOut.nc_IN = "SimpleCutOut.mpr";
          }

        }
        catch (innerErr) {
          console.error("Error while parsing the element: ", innerErr);
        }
      });
    }

    //======================================================================
    // Add the connections
    //======================================================================

    if (Array.isArray(parsed.Connections)) {
      parsed.Connections.forEach((conn: any) => {

        if (conn.type == "Long") {
          const connLong = this.addncout_CountertopConnectionLong();
          connLong.nc_DrawingRelevant = true;
          connLong.nc_MprRelevant = true;
          connLong.nc_LA = conn.length;
          connLong.nc_Position = conn.position;
          connLong.nc_Side = "Top";
          connLong.nc_KO = "00";
          connLong.nc_TOOL = "139";
          connLong.nc_IN = "ConnectionLong.mpr";
        }
        else if (conn.type == "Short") {
          const connShort = this.addncout_CountertopConnectionShort();
          connShort.nc_DrawingRelevant = true;
          connShort.nc_MprRelevant = true;
          connShort.nc_LA = conn.length;
          connShort.nc_Position = conn.position;
          connShort.nc_Side = "Top";
          connShort.nc_KO = "00";
          connShort.nc_TOOL = "139";
          connShort.nc_IN = "ConnectionShort.mpr";
        }
      });
    }

    else {
      console.error("parsed.Countertops is not an array");
    }
  }
  catch (err) {
    console.error("Error while parsing pa_CountertopInfo: ", err);
  }

  //======================================================================
  // Add the edges
  //======================================================================

  let edges = this.addncout_CountertopEdges();
  edges.nc_DrawingRelevant = true;
  edges.nc_MprRelevant = false;
  edges.nc_Side = "Top";
  edges.nc_TOOL = "112";
  edges.nc_EdgesFront = partSelf.pa_EdgeFrontType == "FRE" ? "visible" : "invisible";
  edges.nc_EdgesBack = partSelf.pa_EdgeBackType == "FRE" ? "visible" : "invisible";
  edges.nc_EdgesLeft = partSelf.pa_EdgeLeftType == "FRE" ? "visible" : "invisible";
  edges.nc_EdgesRight = partSelf.pa_EdgeRightType == "FRE" ? "visible" : "invisible";
